import{_ as a,o as e,c as d,ae as r}from"./chunks/framework.BeVX27ge.js";const u=JSON.parse('{"title":"快速開始","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),o={name:"getting-started.md"};function l(h,t,i,n,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="快速開始" tabindex="-1">快速開始 <a class="header-anchor" href="#快速開始" aria-label="Permalink to &quot;快速開始&quot;">​</a></h1><blockquote><p>從登入到完成第一次練習，只需要 5 分鐘</p></blockquote><h2 id="系統需求" tabindex="-1">系統需求 <a class="header-anchor" href="#系統需求" aria-label="Permalink to &quot;系統需求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>需求</th></tr></thead><tbody><tr><td>瀏覽器</td><td>Chrome、Edge、Firefox、Safari 最新版本</td></tr><tr><td>網路</td><td>穩定的網際網路連線</td></tr><tr><td>裝置</td><td>桌面電腦、筆記型電腦、平板（支援 RWD 響應式設計）</td></tr><tr><td>麥克風</td><td>選配，語音輸入功能需要</td></tr></tbody></table><h2 id="登入系統" tabindex="-1">登入系統 <a class="header-anchor" href="#登入系統" aria-label="Permalink to &quot;登入系統&quot;">​</a></h2><p>AI Coach 採用企業級 SSO（單一登入）認證，無需額外註冊帳號。</p><h3 id="登入方式" tabindex="-1">登入方式 <a class="header-anchor" href="#登入方式" aria-label="Permalink to &quot;登入方式&quot;">​</a></h3><p>平台支援以下 SSO 登入方式（依公司設定而異）：</p><ol><li><strong>使用 Microsoft 帳號登入</strong> — 點擊「使用 Microsoft 帳號登入」按鈕，透過公司 Microsoft 帳號完成驗證</li><li><strong>使用 Google 帳號登入</strong> — 點擊「使用 Google 帳號登入」按鈕，透過公司 Google 帳號完成驗證</li></ol><blockquote><p>登入頁面顯示的 SSO 選項依公司部署環境設定，部分環境可能僅提供 Microsoft 登入。</p></blockquote><h3 id="登入流程" tabindex="-1">登入流程 <a class="header-anchor" href="#登入流程" aria-label="Permalink to &quot;登入流程&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>開啟平台網址 → 點擊 SSO 登入按鈕 → 輸入公司帳號密碼 → 自動跳轉至儀表板</span></span></code></pre></div><h3 id="登入異常處理" tabindex="-1">登入異常處理 <a class="header-anchor" href="#登入異常處理" aria-label="Permalink to &quot;登入異常處理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>狀況</th><th>說明</th><th>解決方式</th></tr></thead><tbody><tr><td>帳號未註冊</td><td>您的帳號尚未被管理員加入系統</td><td>聯繫公司管理員新增帳號</td></tr><tr><td>帳號已停用</td><td>頁面顯示「帳號已停用」提示</td><td>聯繫管理員確認帳號狀態</td></tr><tr><td>認證失敗</td><td>顯示「認證失敗，請重新登入後再試」</td><td>重新整理頁面後再試，或清除瀏覽器快取</td></tr><tr><td>請求過於頻繁</td><td>顯示「請求過於頻繁，請稍後再試」</td><td>等待數分鐘後再嘗試</td></tr></tbody></table><h2 id="介面總覽" tabindex="-1">介面總覽 <a class="header-anchor" href="#介面總覽" aria-label="Permalink to &quot;介面總覽&quot;">​</a></h2><p>登入後您會看到以下主要介面區域：</p><h3 id="頁首導覽列" tabindex="-1">頁首導覽列 <a class="header-anchor" href="#頁首導覽列" aria-label="Permalink to &quot;頁首導覽列&quot;">​</a></h3><p>頁面最上方的導覽列包含以下元素（由左至右）：</p><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>AI Coach Logo</td><td>點擊可返回儀表板首頁</td></tr><tr><td>語言切換器</td><td>切換介面語言（繁體中文 / 越南文）</td></tr><tr><td>知識助手圖示</td><td>開啟知識庫智慧問答（需有知識庫閱讀權限）</td></tr><tr><td>管理設定圖示</td><td>進入管理員後台（僅管理員可見）</td></tr><tr><td>登出圖示</td><td>登出系統，會彈出確認對話框：「您確定要登出嗎？」</td></tr></tbody></table><h3 id="主要頁面" tabindex="-1">主要頁面 <a class="header-anchor" href="#主要頁面" aria-label="Permalink to &quot;主要頁面&quot;">​</a></h3><table tabindex="0"><thead><tr><th>頁面</th><th>路徑</th><th>說明</th></tr></thead><tbody><tr><td>儀表板</td><td><code>/dashboard</code></td><td>登入後首頁，顯示學習統計與近期紀錄</td></tr><tr><td>對話練習</td><td><code>/chat</code></td><td>與 AI 客戶進行模擬銷售對話</td></tr><tr><td>評量報告</td><td><code>/review/:sessionId</code></td><td>查看練習的評核結果</td></tr><tr><td>練習歷史</td><td><code>/practice-history</code></td><td>查看所有歷史練習紀錄</td></tr></tbody></table><h2 id="第一次練習-完整流程" tabindex="-1">第一次練習：完整流程 <a class="header-anchor" href="#第一次練習-完整流程" aria-label="Permalink to &quot;第一次練習：完整流程&quot;">​</a></h2><p>以下是從登入到完成第一次練習的完整操作流程：</p><h3 id="步驟-1-登入並查看儀表板" tabindex="-1">步驟 1：登入並查看儀表板 <a class="header-anchor" href="#步驟-1-登入並查看儀表板" aria-label="Permalink to &quot;步驟 1：登入並查看儀表板&quot;">​</a></h3><p>登入後自動進入儀表板。首次使用時統計數字皆為 0，這是正常的。</p><h3 id="步驟-2-開始練習" tabindex="-1">步驟 2：開始練習 <a class="header-anchor" href="#步驟-2-開始練習" aria-label="Permalink to &quot;步驟 2：開始練習&quot;">​</a></h3><p>點擊儀表板上的 <strong>「開始對話」</strong> 按鈕，進入對話練習頁面。</p><h3 id="步驟-3-選擇場景" tabindex="-1">步驟 3：選擇場景 <a class="header-anchor" href="#步驟-3-選擇場景" aria-label="Permalink to &quot;步驟 3：選擇場景&quot;">​</a></h3><p>您會看到兩張場景卡片：</p><table tabindex="0"><thead><tr><th>場景</th><th>說明</th></tr></thead><tbody><tr><td>隨機角色</td><td>系統將為您隨機選擇一個角色進行對話練習。適合快速開始</td></tr><tr><td>自訂角色</td><td>您可以自行定義角色以進行對話練習。適合針對特定情境訓練</td></tr></tbody></table><blockquote><p>建議首次使用選擇 <strong>「隨機角色」</strong>，系統會自動生成完整的客戶角色，讓您快速體驗。</p></blockquote><h3 id="步驟-4-開始對話" tabindex="-1">步驟 4：開始對話 <a class="header-anchor" href="#步驟-4-開始對話" aria-label="Permalink to &quot;步驟 4：開始對話&quot;">​</a></h3><p>選擇場景後，系統會產生客戶角色（需等待數秒）。產生完成後即進入對話介面：</p><ul><li><strong>左側</strong>：客戶資訊側邊欄，顯示客戶的基本資料</li><li><strong>中央</strong>：對話視窗，您可以在此與 AI 客戶交流</li><li><strong>上方</strong>：計時器，記錄練習時長</li></ul><p>在下方輸入框中輸入訊息，按 Enter 或點擊傳送按鈕即可發送。</p><h3 id="步驟-5-結束練習" tabindex="-1">步驟 5：結束練習 <a class="header-anchor" href="#步驟-5-結束練習" aria-label="Permalink to &quot;步驟 5：結束練習&quot;">​</a></h3><p>當您準備結束時，點擊右上方的 <strong>「結束對話」</strong> 按鈕，確認後系統會自動：</p><ol><li>結束對話並儲存紀錄</li><li>開始產生評量報告</li><li>跳轉至評量報告頁面</li></ol><h3 id="步驟-6-查看評量" tabindex="-1">步驟 6：查看評量 <a class="header-anchor" href="#步驟-6-查看評量" aria-label="Permalink to &quot;步驟 6：查看評量&quot;">​</a></h3><p>評量報告產生需要一些時間（通常 30 秒至 2 分鐘），產生完成後您可以看到：</p><ul><li><strong>綜合評核</strong> — 整體表現評估、階段評量、改善建議</li><li><strong>逐句評價</strong> — 每則訊息的詳細回饋</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>了解 <a href="./dashboard.html">儀表板</a> 的完整功能</li><li>深入學習 <a href="./practice.html">對話練習</a> 的進階設定</li><li>瞭解 <a href="./evaluation.html">評量報告</a> 的各項指標</li></ul>',44)])])}const p=a(o,[["render",l]]);export{u as __pageData,p as default};
